code = """import json

# Load books_info query result from file path stored in var_call_mDaUyNRY9bCPCKfpTAT6lvLa
books_file_path = var_call_mDaUyNRY9bCPCKfpTAT6lvLa
with open(books_file_path, 'r', encoding='utf-8') as f:
    books = json.load(f)

# Aggregated review results available as var_call_uzQmeEsSNAKnbPqeQHWVsIz9
avg5_list = var_call_uzQmeEsSNAKnbPqeQHWVsIz9

# Build purchase map
purchase_map = {}
for rec in avg5_list:
    pid = rec.get('purchase_id')
    try:
        avg = float(rec.get('avg_rating'))
    except:
        try:
            avg = float(rec.get('avg_rating', 0))
        except:
            avg = None
    try:
        cnt = int(rec.get('cnt'))
    except:
        cnt = None
    purchase_map[pid] = {'avg_rating': avg, 'cnt': cnt}

# Build book_id -> book record map
book_map = {b['book_id']: b for b in books}

# Filter books for Literature & Fiction and English
lit_eng_book_ids = set()
for b in books:
    cats = b.get('categories') or ''
    det = b.get('details') or ''
    if 'literature & fiction' in cats.lower() or '"Literature & Fiction"' in cats:
        if 'english' in det.lower():
            lit_eng_book_ids.add(b['book_id'])

# Match purchase_ids to book_ids by replacing 'purchaseid_' with 'bookid_'
results = []
for pid, stats in purchase_map.items():
    mapped = pid.replace('purchaseid_', 'bookid_')
    if mapped in lit_eng_book_ids:
        b = book_map.get(mapped, {})
        out = {
            'book_id': mapped,
            'title': b.get('title'),
            'categories': b.get('categories'),
            'details': b.get('details'),
            'purchase_id': pid,
            'avg_rating': stats['avg_rating'],
            'review_count': stats['cnt']
        }
        results.append(out)

# Print result as JSON string per required format
print("__RESULT__:")
print(json.dumps(results))"""

